import { isNil } from 'lodash-es';

type RangeMarker = {
  start: Date | number;
  end: Date | number;
};

type ValueMarker = {
  start: Date | number;
};

export function isRangeMarker(
  range: RangeMarker | ValueMarker,
): range is RangeMarker {
  return 'end' in range && !isNil(range.end) && range.start !== range.end;
}
